import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ColorTypes } from '../../../types/status';
/**
 * Элемент тулбара — кнопка действия с иконкой и/или меню.
 */
export interface ToolbarItemProps {
    /** Текстовая метка кнопки. */
    label?: string;
    /** Иконка кнопки и её цвет. */
    icon?: {
        /** Имя иконки из дизайн-токенов. */
        iconName: Icons;
        /** Цвет из палитры статусов/акцентов. */
        color?: ColorTypes;
    };
    /** Выбранное состояние (активное). */
    selected?: boolean;
    /** Недоступное состояние (disabled). */
    disabled?: boolean;
    /** Обработчик клика по пункту. */
    onClick?: () => void;
    /**
     * Размер элемента. Синхронизируйте с `Toolbar.size`.
     * @default 'medium'
     */
    size?: 'medium' | 'large';
    /**
     * Выпадающее меню элемента.
     * Если задано — рендерится меню, привязанное к элементу.
     */
    menu?: {
        /** Открыто ли меню. Управляется снаружи. */
        isOpen: boolean;
        /** Список пунктов меню. */
        items?: ToolbarItemMenuItem[];
        /** Колбэк по клику вне меню (закрыть). */
        onOutsideClick?: () => void;
        /** (зарезервировано) Колбэк по клику на пункт. */
        onItemClick?: () => void;
    };
}
/**
 * Элемент меню внутри ToolbarItem.
 */
export interface ToolbarItemMenuItem {
    /** Текст пункта меню. */
    title: string;
    /** Иконка пункта меню. */
    iconName?: Icons;
    /** Подзаголовок/описание (опционально). */
    subtitle?: string;
    /** Обработчик клика. */
    onClick?: () => void;
    /** Недоступное состояние. */
    disabled?: boolean;
}
